export const courses = {
'Learn': [<Splash t1='Overview' t2='Learn with Nexus' />],
'Basic': [<Splash t1='Basic' t2='Basic Again' />, <Basic />],
'LeanManufacturing':[<Splash t1='Professional Certificate' t2='Lean Manufacturing' />,<LeanManufacturing />],
